import { NextRequest } from 'next/server'
import { resolveInviteAccess } from '@/lib/invites/access'
import { createServiceClient } from '@/lib/supabase/service'
import { muxUrls, resolveMuxReadyState } from '@/lib/mux'
import { ok, notFound, serverError } from '@/lib/api/response'
import { logger } from '@/lib/logger'

type Params = { params: Promise<{ id: string; assetId: string }> }

const MUX_KINDS = ['opening_video', 'hero_video']
const ASSET_COLUMNS = 'id, kind, status, variants, bytes, duration_ms, mime, created_at, updated_at'

// GET /api/invites/:id/media/:assetId
// Returns current asset status and variants. Poll this until status = 'ready'.
export async function GET(request: NextRequest, { params }: Params) {
  const { id, assetId } = await params
  const result = await resolveInviteAccess(id, request.headers)
  if (!result.ok) return Response.json({ error: result.message }, { status: result.status })

  const service = createServiceClient()
  const { data, error } = await service
    .from('media_assets')
    .select(ASSET_COLUMNS)
    .eq('id', assetId)
    .eq('invite_id', id)
    .single()

  if (error || !data) return notFound('media_asset_not_found')

  // Mux finalizes via webhook, but that can't reach localhost (and may be missed
  // in prod). If a Mux video is still pending, ask Mux directly and self-finalize
  // so the poll resolves without a webhook.
  if (MUX_KINDS.includes(data.kind) && (data.status === 'uploading' || data.status === 'processing')) {
    const reconciled = await reconcileMuxAsset(data, id, assetId, service)
    if (reconciled) return ok(reconciled)
  }

  return ok(data)
}

type AssetRow = {
  id: string
  kind: string
  status: string
  variants: Record<string, unknown> | null
  [key: string]: unknown
}

// Pulls live state from Mux and, if the video is ready/failed, writes the same
// row shape the webhook would. Returns the updated row, or null on no change.
async function reconcileMuxAsset(
  data: AssetRow,
  inviteId: string,
  assetId: string,
  service: ReturnType<typeof createServiceClient>
): Promise<AssetRow | null> {
  const variants = (data.variants ?? {}) as { mux_upload_id?: string; mux_asset_id?: string }
  try {
    const state = await resolveMuxReadyState({
      uploadId: variants.mux_upload_id,
      muxAssetId: variants.mux_asset_id,
    })

    if (state.status === 'pending') return null

    const update =
      state.status === 'ready'
        ? {
            status: 'ready',
            duration_ms: state.durationS ? Math.round(state.durationS * 1000) : null,
            variants: {
              ...variants,
              mux_asset_id: state.muxAssetId,
              playback_id:  state.playbackId,
              hls:          muxUrls.hls(state.playbackId),
              poster:       muxUrls.poster(state.playbackId),
              mp4:          muxUrls.mp4(state.playbackId),
            },
          }
        : { status: 'failed' as const }

    const { data: updated, error } = await service
      .from('media_assets')
      .update(update)
      .eq('id', assetId)
      .eq('invite_id', inviteId)
      .in('status', ['uploading', 'processing'])   // idempotency: lost the race? no-op
      .select(ASSET_COLUMNS)
      .maybeSingle()

    if (error) {
      logger.warn({ event: 'media.reconcile.update_failed', asset_id: assetId, error: error.message })
      return null
    }
    if (updated) logger.info({ event: `media.reconcile.${state.status}`, asset_id: assetId })
    return updated ? (updated as unknown as AssetRow) : null
  } catch (err) {
    // Mux unreachable / not configured — fall back to the stored row.
    logger.warn({ event: 'media.reconcile.failed', asset_id: assetId, error: String(err) })
    return null
  }
}

// DELETE /api/invites/:id/media/:assetId
// Removes the asset row and the backing Storage file (if applicable).
// Mux assets are left to expire naturally — Mux charges per minute, not per asset.
export async function DELETE(request: NextRequest, { params }: Params) {
  const { id, assetId } = await params
  const result = await resolveInviteAccess(id, request.headers)
  if (!result.ok) return Response.json({ error: result.message }, { status: result.status })

  const service = createServiceClient()

  const { data: asset, error: fetchErr } = await service
    .from('media_assets')
    .select('kind, storage_key')
    .eq('id', assetId)
    .eq('invite_id', id)
    .single()

  if (fetchErr || !asset) return notFound('media_asset_not_found')

  // Delete Storage file for non-Mux assets
  const MUX_KINDS = ['opening_video', 'hero_video']
  if (!MUX_KINDS.includes(asset.kind) && asset.storage_key) {
    const { error: storageErr } = await service.storage
      .from('invite-media')
      .remove([asset.storage_key])

    if (storageErr) {
      // Log but don't abort — delete the DB row regardless
      logger.warn({ event: 'storage.delete.failed', asset_id: assetId, error: storageErr.message })
    }
  }

  const { error } = await service
    .from('media_assets')
    .delete()
    .eq('id', assetId)
    .eq('invite_id', id)

  if (error) {
    logger.error({ event: 'media_asset.delete.failed', asset_id: assetId, error: error.message })
    return serverError()
  }

  return new Response(null, { status: 204 })
}
